<?php try { $p=new PDO('mysql:host=localhost;dbname=feedback_db', 'root', ''); } catch(Exception $e) { die('DB Error'); } if ($_SERVER['REQUEST_METHOD']==='POST') { $d=$_POST; $s=$p->prepare('INSERT INTO respondent(id_event,full_name,email_1,company_name,job_title,mobile_phone)VALUES(?,?,?,?,?,?)'); $s->execute([$d['id_event']??'909', $d['name']??'', $d['email']??'', $d['companyName']??'', $d['jobTitle']??'', $d['mobileNumber']??'']); $rid=$p->lastInsertId(); $s=$p->prepare('INSERT INTO answer(id_feedback,id_respondent,id_question,answer_text)VALUES(?,?,?,?)'); foreach(["name","q_30","email","q_31","companyName","mobileNumber"] as $k) { if(isset($d[$k])) { $v=is_array($d[$k])?implode('; ',$d[$k]):$d[$k]; $s->execute([$d['id_event']??'909', $rid, $k, $v]); } } header('Location:index.php?ok'); exit; } header('Location:index.php');